import{_ as e,o as n,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"77. Best Practice Employment Commitment Committee","description":"","frontmatter":{"title":"77. Best Practice Employment Commitment Committee","eba":"Doctors in Training 2022-2026","topics":["union-matters","preliminary","staffing","workload"]},"headers":[],"relativePath":"ebas/doctors-in-training/union-matters/77-best-practice-employment-commitment-committee.md","filePath":"ebas/doctors-in-training/union-matters/77-best-practice-employment-commitment-committee.md"}'),r={name:"ebas/doctors-in-training/union-matters/77-best-practice-employment-commitment-committee.md"};function a(s,t,m,c,p,l){return n(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="_77-best-practice-employment-commitment-committee" tabindex="-1">77. Best Practice Employment Commitment Committee <a class="header-anchor" href="#_77-best-practice-employment-commitment-committee" aria-label="Permalink to &quot;77. Best Practice Employment Commitment Committee&quot;">​</a></h1><p><strong>77.1</strong> The parties agree to establish a committee to discuss Best Practice Employment Commitments (BPEC) during the life of the Agreement on matters including:</p><p><strong>(a)</strong> measures to identify and respond to workload including:</p><p><strong>(i)</strong> Discussion regarding reports and activities relevant to workforce planning; and</p><p><strong>(ii)</strong> Invite additional attendees to discuss workforce matters;</p><p><strong>(b)</strong> climate change initiatives to reduce carbon and other harmful emissions within the public health system including:</p><p><strong>(i)</strong> discussion regarding the environmental performance of Employers published in accordance with the Department’s environmental guidelines;</p><p><strong>(ii)</strong> discussion regarding any reports or activities of other bodies such as Global Green and Healthy Hospitals that are relevant to the reduction of carbon emissions;</p><p><strong>(iii)</strong> promotion of initiatives taken by an Employer and / or Employees to reduce carbon and other harmful emissions; and</p><p><strong>(iv)</strong> invite external interest groups, unions or other organisations to discuss the impacts the public health system as a whole has on producing harmful emissions and any initiatives to reduce these;</p><p><strong>(c)</strong> the development of an agreed ‘best practice guide’ with respect to workplace bullying based on WorkSafe’s ‘Guide for Employers’ dated March 2020;</p><p><strong>(d)</strong> template change impact statements;</p><p><strong>(e)</strong> collaboration between the parties to reduce duplication of training and promote recognition of training across Health Services;</p><p><strong>(f)</strong> collaboration between the parties to monitor onboarding and credentialing practices to identify opportunities for common application requirements and the implementation of electronic onboarding and credentialing;</p><p>Plain language terms: BPEC.</p>',15)])])}const h=e(r,[["render",a]]);export{g as __pageData,h as default};
